<template>
  <div>
    <p style="" v-if="result.length > 0">排名
      <a-switch @click="rankChange" v-model="rank"/>
      <span style="float: right;">点击卡片进入被评人分数详情</span>
    </p>
    <p style="text-align: center;" v-else-if="loading">加载中</p>
    <p style="text-align: center;" v-else>当前暂无评分</p>
    <a-card style="width: 100%; margin: 14px 0; border-radius: 4px;" v-for="(item, index) in rank ? resultRanked : result" :key="index" v-if="!loading" @click="route2Details(item.contestantId)">
      <div style="width: 100%; display: flex;">
        <div v-if="rank" style="width: 40px; display: flex; align-items: center; justify-content: center;">
          <span style="font-size: 20px; font-weight: bold; color: #333;">{{ resultRankedFilter.indexOf(item.finalScore) + 1 }}</span>
        </div>
        <div style="width: calc(100% - 80px);" :style="{ 'margin-left': rank ? '8px' : '0' }">
          <h2 style="margin-bottom: 4px;">{{ item.contestantName }}</h2>
          <p style="margin-bottom: 0; font-size: 16px; color: #888">{{ item.description }}</p>
        </div>
        <div style="width: 80px; display: flex; align-items: center; justify-content: center;">
          <span style="float: right; font-size: 16px; margin-top: 4px; font-weight: 700;">{{ item.finalScore.toFixed(2) }}分</span>
        </div>
      </div>
    </a-card>
    <!-- <a-button type="primary" style="width: 100%; height: 48px; font-size: 24px;" @click="openScreen">
      展示大屏
    </a-button> -->
  </div>
</template>
<script>
import { getContestantScoresWithoutRemoving, getContestantScoresRankedWithoutRemoving } from '@/api/dataAnalysis'
export default {
  data() {
    return {
      loading: false,
      form: {},
      result: [],
      resultRanked: [],
      rank: false,
      refreshTimer: null, // 添加定时器变量
    }
  },
  mounted() {
    this.loadData()
    this.rank = this.$route.query.rank === 'true'
    // 设置定时器，每隔8000毫秒刷新一次数据
    this.startAutoRefresh()
  },
  beforeDestroy() {
    // 组件销毁前清除定时器，防止内存泄漏
    this.stopAutoRefresh()
  },
  computed: {
    resultRankedFilter() {
      return this.resultRanked.map(item => item.finalScore)
    },
  },
  methods: {
    loadData() {
      this.loading = true
      getContestantScoresWithoutRemoving(this.$route.params.id).then(res => {
        this.result = res
      }).finally(() => {
        this.loading = false
      })
      getContestantScoresRankedWithoutRemoving(this.$route.params.id).then(res => {
        this.resultRanked = res
      })
    },
    slienceLoadData() {
      getContestantScoresWithoutRemoving(this.$route.params.id).then(res => {
        this.result = res
      })
      getContestantScoresRankedWithoutRemoving(this.$route.params.id).then(res => {
        this.resultRanked = res
      })
    },
    // 启动自动刷新
    startAutoRefresh() {
      // 先清除已有的定时器
      this.stopAutoRefresh()
      // 设置新的定时器
      this.refreshTimer = setInterval(() => {
        this.slienceLoadData()
      }, 8000)
    },
    // 停止自动刷新
    stopAutoRefresh() {
      if (this.refreshTimer) {
        clearInterval(this.refreshTimer)
        this.refreshTimer = null
      }
    },
    openScreen() {
      window.open(`/#/dataDisplay/${this.$route.params.id}`, '_blank')
    },
    route2Details(cid) {
      this.$router.push({
        name: 'contestantVoteData',
        params: {
          id: this.$route.params.id,
          cid: cid,
        },
      })
    },
    rankChange(e) {
      this.$router.replace({ query: { rank: e } })
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 16px 8px 12px 12px !important;
}
</style>
